import json
import os
from typing import Any, Dict

from rich.console import Console
from rich.syntax import Syntax
from rich.padding import Padding
from rich.tree import Tree

# Assuming TreeWrapper is defined in the same package
from .tree_wrapper import TreeWrapper

_console = Console(force_terminal=False, width=120)


def decode_if_json(content: Any) -> Any:
    if isinstance(content, str):
        try:
            return json.loads(content)
        except Exception:
            return insert_newlines(content)
    return content


def _add_rag_matches(root: TreeWrapper, content: Dict[str, Any]) -> bool:
    """Add RAG matches to the provided tree."""
    if not ("matches" in content and isinstance(content["matches"], list)):
        return False

    matches = content["matches"]
    for idx, match in enumerate(matches, start=1):
        file = match.get("file")
        text = match.get("text", "")

        # skip pre‑approved files when SHOW_ALL is falsy
        if not SHOW_ALL and file and is_preapproved(str(file)):
            continue

        header = f"## MATCH {idx}"
        if file:
            header += f": [bold]{file}[/]"
        match_node: Tree = root.add(header)

        if isinstance(text, str):
            ext = os.path.splitext(file)[1].lstrip(".").lower() if file else ""
            syntax = Syntax(text, ext or "text", theme="default", word_wrap=True)
            match_node.add(syntax)
        else:
            match_node.add("[red bold]UNEXPECTED 'text' field type (rag matches s/b str only):[/]")
            match_node.add(pprint_no_truncate(text))

    return True


def _add_mcp_result(root: TreeWrapper, content: Dict[str, Any]) -> bool:
    """Add MCP result content to the provided tree."""
    if not ("content" in content and isinstance(content["content"], list)):
        return False

    for item in content["content"]:
        item_type = yank(item, "type")
        name = yank(item, "name")
        if name:
            root.add(f"[white]{name}:[/]")
        if item_type == "text":
            item_text = insert_newlines(yank(item, "text"))
            root.add(item_text)

    return True


def _add_unrecognized(root: TreeWrapper, content: Any) -> None:
    root.add("[yellow bold]UNRECOGNIZED RESULT TYPE:[/]")
    root.add(pprint_no_truncate(content))


def print_tool_result_message(msg: Dict[str, Any]) -> None:
    """Build a rich tree for a tool result and print it."""
    content = decode_if_json(msg.get("content", ""))
    tree_root = TreeWrapper("Tool Result")

    if not isinstance(content, dict):
        tree_root.add(pprint_no_truncate(content))
        _console.print(tree_root)
        return

    handled = (
        _add_rag_matches(tree_root, content)
        or _add_mcp_result(tree_root, content)
    )
    if not handled:
        _add_unrecognized(tree_root, content)

    _console.print(tree_root)
